import{_ as s,o as e,c as i,a2 as o}from"./chunks/framework.CGYl2SZ_.js";const l=JSON.parse('{"title":"session tool","description":"session tool 页面","frontmatter":{"title":"session tool","description":"session tool 页面"},"headers":[],"relativePath":"concepts/session-tool.md","filePath":"concepts/session-tool.md"}');const a=s({name:"concepts/session-tool.md"},[["render",function(s,l,a,n,t,d){return e(),i("div",null,[...l[0]||(l[0]=[o('<h1 id="会话工具" tabindex="-1">会话工具 <a class="header-anchor" href="#会话工具" aria-label="Permalink to &quot;会话工具&quot;">​</a></h1><h1 id="会话工具-1" tabindex="-1">会话工具 <a class="header-anchor" href="#会话工具-1" aria-label="Permalink to &quot;会话工具&quot;">​</a></h1><p>目标：小巧、难以误用的工具集，以便代理可以列出会话、获取历史和发送到另一个会话。</p><h2 id="工具名称" tabindex="-1">工具名称 <a class="header-anchor" href="#工具名称" aria-label="Permalink to &quot;工具名称&quot;">​</a></h2><ul><li><code>sessions_list</code></li><li><code>sessions_history</code></li><li><code>sessions_send</code></li><li><code>sessions_spawn</code></li></ul><h2 id="关键模型" tabindex="-1">关键模型 <a class="header-anchor" href="#关键模型" aria-label="Permalink to &quot;关键模型&quot;">​</a></h2><ul><li>主直接聊天桶始终是字面键 <code>&quot;main&quot;</code>（解析为当前代理的主键）。</li><li>群组聊天使用 <code>agent:&lt;agentId&gt;:&lt;channel&gt;:group:&lt;id&gt;</code> 或 <code>agent:&lt;agentId&gt;:&lt;channel&gt;:channel:&lt;id&gt;</code>（传递完整键）。</li><li>Cron 作业使用 <code>cron:&lt;job.id&gt;</code>。</li><li>钩子使用 <code>hook:&lt;uuid&gt;</code>，除非明确设置。</li><li>节点会话使用 <code>node-&lt;nodeId&gt;</code>，除非明确设置。</li></ul><p><code>global</code> 和 <code>unknown</code> 是保留值，永不列出。如果 <code>session.scope = &quot;global&quot;</code>，我们为所有工具将其别名为 <code>main</code>，以便调用者永远不会看到 <code>global</code>。</p><h2 id="sessions-list" tabindex="-1">sessions_list <a class="header-anchor" href="#sessions-list" aria-label="Permalink to &quot;sessions_list&quot;">​</a></h2><p>将会话列为行数组。</p><p>参数：</p><ul><li><code>kinds?: string[]</code> 过滤：任何 <code>&quot;main&quot; | &quot;group&quot; | &quot;cron&quot; | &quot;hook&quot; | &quot;node&quot; | &quot;other&quot;</code></li><li><code>limit?: number</code> 最大行数（默认：服务器默认，例如限制为 200）</li><li><code>activeMinutes?: number</code> 仅 N 分钟内更新的会话</li><li><code>messageLimit?: number</code> 0 = 无消息（默认 0）；&gt;0 = 包含最后 N 条消息</li></ul><p>行为：</p><ul><li><code>messageLimit &gt; 0</code> 每个会话获取 <code>chat.history</code> 并包含最后 N 条消息。</li><li>列表输出中过滤掉工具结果；使用 <code>sessions_history</code> 获取工具消息。</li><li>在<strong>沙盒化</strong>的代理会话中运行时，会话工具默认为<strong>仅生成可见性</strong>（见下文）。</li></ul><p>行形状（JSON）：</p><ul><li><code>key</code>：会话键（字符串）</li><li><code>kind</code>：<code>main | group | cron | hook | node | other</code></li><li><code>channel</code>：<code>whatsapp | telegram | discord | signal | imessage | webchat | internal | unknown</code></li><li><code>displayName</code>（群组显示标签，如果有）</li><li><code>updatedAt</code>（毫秒）</li><li><code>sessionId</code></li><li><code>model</code>、<code>contextTokens</code>、<code>totalTokens</code></li><li><code>thinkingLevel</code>、<code>verboseLevel</code>、<code>systemSent</code>、<code>abortedLastRun</code></li><li><code>sendPolicy</code>（如果设置，会话覆盖）</li><li><code>lastChannel</code>、<code>lastTo</code></li><li><code>deliveryContext</code>（规范化 <code>{ channel, to, accountId }</code>，如果有）</li><li><code>transcriptPath</code>（来自存储目录 + sessionId 的尽力路径）</li><li><code>messages?</code>（仅当 <code>messageLimit &gt; 0</code>）</li></ul><h2 id="sessions-history" tabindex="-1">sessions_history <a class="header-anchor" href="#sessions-history" aria-label="Permalink to &quot;sessions_history&quot;">​</a></h2><p>获取一个会话的记录。</p><p>参数：</p><ul><li><code>sessionKey</code>（必需；接受会话键或 <code>sessions_list</code> 中的 <code>sessionId</code>）</li><li><code>limit?: number</code> 最大消息数（服务器限制）</li><li><code>includeTools?: boolean</code>（默认 false）</li></ul><p>行为：</p><ul><li><code>includeTools=false</code> 过滤 <code>role: &quot;toolResult&quot;</code> 消息。</li><li>以原始记录格式返回消息数组。</li><li>给定 <code>sessionId</code>，OpenClaw 解析为对应的会话键（缺失 ID 报错）。</li></ul><h2 id="sessions-send" tabindex="-1">sessions_send <a class="header-anchor" href="#sessions-send" aria-label="Permalink to &quot;sessions_send&quot;">​</a></h2><p>向另一个会话发送消息。</p><p>参数：</p><ul><li><code>sessionKey</code>（必需；接受会话键或 <code>sessions_list</code> 中的 <code>sessionId</code>）</li><li><code>message</code>（必需）</li><li><code>timeoutSeconds?: number</code>（默认 &gt;0；0 = 发送后不管）</li></ul><p>行为：</p><ul><li><code>timeoutSeconds = 0</code>：入队并返回 <code>{ runId, status: &quot;accepted&quot; }</code>。</li><li><code>timeoutSeconds &gt; 0</code>：等待最多 N 秒完成，然后返回 <code>{ runId, status: &quot;ok&quot;, reply }</code>。</li><li>如果等待超时： <code>{ runId, status: &quot;timeout&quot;, error }</code>。运行继续；稍后调用 <code>sessions_history</code>。</li><li>如果运行失败： <code>{ runId, status: &quot;error&quot;, error }</code>。</li><li>宣布传递在主运行完成后运行，是尽力而为的；<code>status: &quot;ok&quot;</code> 不保证宣布已传递。</li><li>通过网关 <code>agent.wait</code>（服务器端）等待，因此重新连接不会丢失等待。</li><li>代理到代理消息上下文为主运行注入。</li><li>跨会话消息用 <code>message.provenance.kind = &quot;inter_session&quot;</code> 持久化，以便记录读者可以将路由的代理指令与外部用户输入区分开来。</li><li>主运行完成后，OpenClaw 运行<strong>回复循环</strong>： <ul><li>第 2+ 轮在请求者和目标代理之间交替。</li><li>精确回复 <code>REPLY_SKIP</code> 停止 ping-pong。</li><li>最大轮次是 <code>session.agentToAgent.maxPingPongTurns</code>（0-5，默认 5）。</li></ul></li><li>循环结束后，OpenClaw 运行<strong>代理到代理宣布步骤</strong>（仅目标代理）： <ul><li>精确回复 <code>ANNOUNCE_SKIP</code> 保持沉默。</li><li>任何其他回复发送到目标渠道。</li><li>宣布步骤包括原始请求 + 第 1 轮回复 + 最新的 ping-pong 回复。</li></ul></li></ul><h2 id="渠道字段" tabindex="-1">渠道字段 <a class="header-anchor" href="#渠道字段" aria-label="Permalink to &quot;渠道字段&quot;">​</a></h2><ul><li>对于群组，<code>channel</code> 是会话条目上记录的渠道。</li><li>对于直接聊天，<code>channel</code> 从 <code>lastChannel</code> 映射。</li><li>对于 cron/hook/node，<code>channel</code> 是 <code>internal</code>。</li><li>如果缺失，<code>channel</code> 是 <code>unknown</code>。</li></ul><h2 id="安全-发送策略" tabindex="-1">安全 / 发送策略 <a class="header-anchor" href="#安全-发送策略" aria-label="Permalink to &quot;安全 / 发送策略&quot;">​</a></h2><p>基于渠道/聊天类型的策略阻止（不是每个会话 ID）。</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;session&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;sendPolicy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;rules&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;match&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;channel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;discord&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;chatType&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;deny&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      ],</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;default&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allow&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>运行时覆盖（每个会话条目）：</p><ul><li><code>sendPolicy: &quot;allow&quot; | &quot;deny&quot;</code>（未设置 = 继承配置）</li><li>可通过 <code>sessions.patch</code> 或仅所有者 <code>/send on|off|inherit</code>（独立消息）设置。</li></ul><p>执行点：</p><ul><li><code>chat.send</code> / <code>agent</code>（网关）</li><li>自动回复传递逻辑</li></ul><h2 id="sessions-spawn" tabindex="-1">sessions_spawn <a class="header-anchor" href="#sessions-spawn" aria-label="Permalink to &quot;sessions_spawn&quot;">​</a></h2><p>在隔离会话中生成子代理运行，并将结果宣布回请求者聊天渠道。</p><p>参数：</p><ul><li><code>task</code>（必需）</li><li><code>label?</code>（可选；用于日志/UI）</li><li><code>agentId?</code>（可选；如果允许，在另一个代理 ID 下生成）</li><li><code>model?</code>（可选；覆盖子代理模型；无效值报错）</li><li><code>thinking?</code>（可选；覆盖子代理运行的推理级别）</li><li><code>runTimeoutSeconds?</code>（默认为 <code>agents.defaults.subagents.runTimeoutSeconds</code>（如果设置），否则为 <code>0</code>；设置时，在 N 秒后中止子代理运行）</li><li><code>thread?</code>（默认 false；请求时支持的渠道/插件的线程绑定路由）</li><li><code>mode?</code>（<code>run|session</code>；默认为 <code>run</code>，但 <code>thread=true</code> 时默认为 <code>session</code>；<code>mode=&quot;session&quot;</code> 需要 <code>thread=true</code>）</li><li><code>cleanup?</code>（<code>delete|keep</code>，默认 <code>keep</code>）</li><li><code>sandbox?</code>（<code>inherit|require</code>，默认 <code>inherit</code>；<code>require</code> 拒绝生成除非目标子运行时是沙盒化的）</li><li><code>attachments?</code>（可选的内联文件数组；仅子代理运行时，ACP 拒绝）。每个条目：<code>{ name, content, encoding?: &quot;utf8&quot; | &quot;base64&quot;, mimeType? }</code>。文件在子工作空间的 <code>.openclaw/attachments/&lt;uuid&gt;/</code> 中具体化。返回每个文件的 sha256 收据。</li><li><code>attachAs?</code>（可选；<code>{ mountPath? }</code> 提示保留用于未来挂载实现）</li></ul><p>白名单：</p><ul><li><code>agents.list[].subagents.allowAgents</code>：允许通过 <code>agentId</code> 的代理 ID 列表（<code>[&quot;*&quot;]</code> 允许任何）。默认：仅请求者代理。</li><li>沙盒继承守卫：如果请求者会话是沙盒化的，<code>sessions_spawn</code> 拒绝将运行非沙盒化的目标。</li></ul><p>发现：</p><ul><li>使用 <code>agents_list</code> 发现允许 <code>sessions_spawn</code> 的代理 ID。</li></ul><p>行为：</p><ul><li>使用 <code>deliver: false</code> 启动新的 <code>agent:&lt;agentId&gt;:subagent:&lt;uuid&gt;</code> 会话。</li><li>子代理默认为完整工具集<strong>减去会话工具</strong>（可通过 <code>tools.subagents.tools</code> 配置）。</li><li>子代理不允许调用 <code>sessions_spawn</code>（不允许子代理 → 子代理生成）。</li><li>始终非阻塞：立即返回 <code>{ status: &quot;accepted&quot;, runId, childSessionKey }</code>。</li><li>带 <code>thread=true</code>，渠道插件可以将传递/路由绑定到线程目标（Discord 支持由 <code>session.threadBindings.*</code> 和 <code>channels.discord.threadBindings.*</code> 控制）。</li><li>完成后，OpenClaw 运行子代理<strong>宣布步骤</strong>并将结果发布到请求者聊天渠道。 <ul><li>如果助手最终回复为空，则包含子代理历史记录中的最新 <code>toolResult</code> 作为 <code>Result</code>。</li></ul></li><li>在宣布步骤中精确回复 <code>ANNOUNCE_SKIP</code> 保持沉默。</li><li>宣布回复规范化为 <code>Status</code>/<code>Result</code>/<code>Notes</code>；<code>Status</code> 来自运行时结果（不是模型文本）。</li><li>子代理会话在 <code>agents.defaults.subagents.archiveAfterMinutes</code>（默认：60）后自动归档。</li><li>宣布回复包括统计行（运行时、令牌、sessionKey/sessionId、记录路径和可选成本）。</li></ul><h2 id="沙盒会话可见性" tabindex="-1">沙盒会话可见性 <a class="header-anchor" href="#沙盒会话可见性" aria-label="Permalink to &quot;沙盒会话可见性&quot;">​</a></h2><p>会话工具可以限定范围以减少跨会话访问。</p><p>默认行为：</p><ul><li><code>tools.sessions.visibility</code> 默认为 <code>tree</code>（当前会话 + 生成的子代理会话）。</li><li>对于沙盒会话，<code>agents.defaults.sandbox.sessionToolsVisibility</code> 可以硬限制可见性。</li></ul><p>配置：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    sessions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      // &quot;self&quot; | &quot;tree&quot; | &quot;agent&quot; | &quot;all&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      // 默认：&quot;tree&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      visibility</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tree&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      sandbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // 默认：&quot;spawned&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        sessionToolsVisibility</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;spawned&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 或 &quot;all&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>注意：</p><ul><li><code>self</code>：仅当前会话键。</li><li><code>tree</code>：当前会话 + 当前会话生成的会话。</li><li><code>agent</code>：属于当前代理 ID 的任何会话。</li><li><code>all</code>：任何会话（跨代理访问仍需要 <code>tools.agentToAgent</code>）。</li><li>当会话沙盒化且 <code>sessionToolsVisibility=&quot;spawned&quot;</code> 时，OpenClaw 将可见性限制为 <code>tree</code>，即使您设置 <code>tools.sessions.visibility=&quot;all&quot;</code>。</li></ul>',55)])])}]]);export{l as __pageData,a as default};
